effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float luminance = dot(texColor.rgb, luminanceWeighting);
    float f = max(min((feather/4.),abs(0.5-threshold)),0.00196);
    float t = ((threshold-0.5)*(1.003+f*2.))+0.5;
    float p = smoothstep(t-f, t+f, luminance);

    if( invert )
        p = 1.-p;

    vec3 rgb;
    if( blendMode==1 ) {
        rgb = texColor.rgb * p;
    } else if( blendMode==2 ) {
        rgb = 1.-((1.-texColor.rgb)*(1.-p));
    } else {
        rgb = vec3(p,p,p);
    }

    gl_FragColor = vec4(rgb,texColor.a);
}
